class Singleton {
  private static instance: Singleton;
  private constructor() {}
  public static getInstance(): Singleton {
    if (!Singleton.instance) {
      Singleton.instance = new Singleton();
    }
    return Singleton.instance;
  }
}

class Director {
  private builder: Builder;
  constructor(builder: Builder) {
    this.builder = builder;
  }
  public construct(): void {
    this.builder.buildPartA();
    this.builder.buildPartB();
  }
}

interface AbstractFactory {
  createProductA(): AbstractProductA;
  createProductB(): AbstractProductB;
}

class Proxy {
  private realSubject: RealSubject;
  constructor(realSubject: RealSubject) {
    this.realSubject = realSubject;
  }
  public request(): void {
    if (this.checkAccess()) {
      this.realSubject.request();
      this.logAccess();
    }
  }
}

class Composite implements Component {
  private children: Component[] = [];
  public add(component: Component): void {
    this.children.push(component);
  }
  public operation(): string {
    return this.children.map(child => child.operation()).join('+');
  }
}

class Decorator implements Component {
  protected component: Component;
  constructor(component: Component) {
    this.component = component;
  }
  public operation(): string {
    return `Decorator(${this.component.operation()})`;
  }
}

class Context {
  private strategy: Strategy;
  constructor(strategy: Strategy) {
    this.strategy = strategy;
  }
  public executeStrategy(): void {
    this.strategy.doAlgorithm();
  }
}

class Mediator {
  private components: Component[] = [];
  public register(component: Component): void {
    this.components.push(component);
  }
  public notify(sender: Component, event: string): void {
    // Handle interaction
  }
}

class Subject {
  private observers: Observer[] = [];
  public attach(observer: Observer): void {
    this.observers.push(observer);
  }
  public notify(): void {
    for (const observer of this.observers) {
      observer.update(this);
    }
  }
}
